  ('elementary-6e11b43e-moex-00189', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '19 世紀後期到臺灣南部傳教及行醫，是英國長老會第一位駐臺灣宣教師，在臺期間，足跡遍及玉山及中 央山脈，翻山越嶺，深入平埔族各部落行醫傳道。請問為下列那一位牧師？', '["馬偕牧師", "馬雅各牧師", "巴克禮牧師", "尤紐斯牧師"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00190', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '中華民國於那一年宣布實施每年8月1日為原住民族日？', '["2005", "1984", "1994", "2004"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00191', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '1994年中華民國總統首先在那裡宣布將山胞改為原住民？', '["總統府", "內政部", "臺灣山地文化園區（現為原住民文化園區）", "花蓮縣政府"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00192', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '關於當代太魯閣正名運動的發生，下列敘述何者錯誤？', '["太魯閣正名主要是居住地變遷與政治權益等政治權利行使，與語言差異無關", "1914年的太魯閣戰役後，重構太魯閣族群的集體記憶，族群產生不同的認知", "太魯閣族部落主要分布於秀林、萬榮、卓溪三鄉", "Truku的正名運動自1996年7月10日太魯閣中會教社部在富世村姬望教會首次舉行研討會提出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00193', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '1980年代以後面對原運行動者的訴求，政府以「增」、「劃」編的方式回應之。至2000年，隨著總統與 原住民族代表簽訂「新夥伴關係」之協議，在原運已經被提出來的「傳統領域」的概念逐漸進入統治者的 視野。下列敘述何者正確？', '["傳統領域與所有權類似", "傳統領域的權利不包括自然資源運用", "2004年森林法將原住民族於傳統領域之林產物採取行為增列除罪條款", "傳統領域並不包括平地的原住民族"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00194', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '牡丹社事件排灣族勇士的頭骨，經過愛丁堡大學正式歸還，目前暫存於何處？', '["屏東縣牡丹鄉公所", "屏東縣政府", "國立臺灣博物館", "國立臺灣史前文化博物館南科分館"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00195', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-d3860915', 'sub-elementary-6e11b43e-04', NULL, 'single_choice', '牡丹社事件150週年紀念，屏東縣政府依文化資產保存法將macacukes石門古戰場公告為那一類文化資產？', '["古蹟", "歷史建築", "考古遺址", "史蹟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "c46ab9e1eec6", "answer_pdf_sha1": "1daf66ee7f02", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臺灣原住民族史大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00001', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '目前各國衡量一國的經濟成長常會使用國民所得的數據來顯示，但國民所得的數據只是整體與平均經濟 狀況表象，下列何種曲線可以呈現國民所得分配不均程度？', '["恩格爾曲線", "菲利浦曲線", "勞倫斯曲線", "生產可能曲線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00002', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '某國生產兩種產品（X與Y，分別表示為水平軸與垂直軸），其凹向原點的生產可能曲線上，由左上往右 下依序為A、B、C三個點，下列敘述何者正確？', '["就生產效率的大小而言，A＞B＞C", "多生產一單位X的機會成本為A＞B＞C", "就生產效率的大小而言，A＝B＝C", "多生產一單位Y的機會成本為A＝B＝C"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00003', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-114-b3f42868', 'sub-elementary-6f0ba476-01', NULL, 'single_choice', '跨太平洋夥伴全面進步協定（CPTPP）旨在促進泛太平洋國家間的貿易自由化。依其宗旨判斷，參與此種 經濟合作組織的國家，會產生下列何種現象？', '["勞動要素可自由流動", "各國間實施關稅保護", "共同發行統一的貨幣", "市場上商品種類增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:37+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
